/* eslint-disable prefer-destructuring */
import {
  ref, reactive, getCurrentInstance, toRefs
} from "vue";
import Web3, { utils } from "web3";
import Web3Modal from "web3modal";
import { getChainData } from "@/web3/tools"; // 通过 chainId 获取链配置
import { providerOptions } from "@/web3/config";// 多个 provider
// 预设状态变量
const INITIAL_STATE = {
  web3: null, // web3 库
  provider: null, // 选择使用的 provider
  userAddress: "", // 用户地址
  connected: false, // 是否连接钱包
  chainId: 1,
  networkId: 1
};
export default function UseWallet() {
  const { ctx: _this } = getCurrentInstance();// 当前组件实例

  // 初始化响应变量
  const walletObj = reactive({ ...INITIAL_STATE });
  const fetching = ref(false);
  const assets = ref(0);

  // https://github.com/Web3Modal/web3modal#web3modal
  const web3Modal = new Web3Modal({
    // theme: "dark",
    network: getChainData(walletObj.chainId).network,
    cacheProvider: true,
    providerOptions
  });
  // 重置连接 methods wallte.js
  const resetApp = async () => {
    const { web3 } = walletObj;
    if (web3) {
      console.log("web3 of wallet has set:", web3);
    }
    // 如果 web3 已经配置好了
    if (web3 && web3.currentProvider && web3.currentProvider.close) {
      // console.log("web3 has settled and the closed");
      await web3.currentProvider.close();
    }
    console.log("not set web3 and then close provider.");
    web3Modal.clearCachedProvider();
    assets.value = 0;
    // 状态响应重置为默认状态
    Object.keys(INITIAL_STATE).forEach((e) => {
      walletObj[e] = INITIAL_STATE[e];
    });
    // 强制渲染页面，避免组件自动渲染的延迟
    _this.$forceUpdate();
  };
  const getUserBalance = () => walletObj.web3.eth
    .getBalance(walletObj.userAddress)
    .then((res) => {
      console.log("get current account's balance", res.toString());
      return (res ? utils.fromWei(res.toString(), "ether") : 0);
    });

  const getAccountAssets = async () => {
    fetching.value = true; // 标志已经获取余额
    // get account balances

    assets.value = await getUserBalance();
  };
  // 监听 provider 事件，用于改变连接状态时更新页面
  // provider 一般都满足 EIP-1193 标准
  const subscribeProvider = async (provider) => {
    if (!provider.on) {
      return;
    }
    provider.on("close", () => resetApp());
    provider.on("accountsChanged", async (accounts) => {
      walletObj.userAddress = accounts[0];
      await getAccountAssets();
    });
    provider.on("chainChanged", async (chainId) => {
      console.log("new chainId is", chainId);
      // 判空，如果对象中有一个未加载成功就为空
      const networkId = await walletObj?.web3?.eth?.net.getId();
      walletObj.chainId = chainId;
      walletObj.networkId = networkId;
      await getAccountAssets();
    });
  };

  // 连接钱包
  const onConnect = async () => {
    // 由 web3modal 触发连接
    const provider = await web3Modal.connect();

    await subscribeProvider(provider);

    // 初始化 web3
    const web3 = new Web3(provider);
    const accounts = await web3.eth.getAccounts();

    const address = accounts[0];

    const networkId = await web3.eth.net.getId();

    const chainId = await web3.eth.getChainId(); // 坑逼 注意版本 chainId

    // 初始化钱包对象
    walletObj.web3 = web3;
    walletObj.provider = provider;
    walletObj.connected = true;
    walletObj.userAddress = address;
    walletObj.chainId = chainId;
    walletObj.networkId = networkId;
    await getAccountAssets();
  };

  return {
    // 转换成普通对象，当时元素仍然保持响应性，并且解包
    ...toRefs(walletObj),
    fetching, // 是否已经获取余额
    assets, // 余额
    resetApp, // 重置连接
    getAccountAssets, // 查询余额
    //
    web3Modal, // 响应式的 web3Modal 对象
    // methods
    onConnect
  };
}
